// Modo PERFIL — preparar payload pra dois actors
const body = $json.body;
return [{ json: {
  username: body.username,
  trilha: body.trilha,
  coletar_fixados: body.coletar?.posts_fixados !== false,
  coletar_destaques: body.coletar?.destaques !== false,
  transcrever: body.coletar?.transcrever !== false,
  notas: body.notas || '',
  origem: body.origem || 'manual_form',
  created_at: body.created_at
}}];

// Mescla resultados dos dois actors em itens normalizados
const meta = $('Preparar Perfil').first().json;
const profileData = $('Apify Profile Scraper (Fixados)').first()?.json || [];
const highlightsData = $('Apify Highlights (Destaques)').first()?.json || [];

const items = [];

// Posts fixados
if (meta.coletar_fixados && Array.isArray(profileData) && profileData[0]) {
  const profile = profileData[0];
  const pinned = (profile.latestPosts || []).filter(p => p.isPinned);
  pinned.sort((a,b)=>(a.timestamp||'').localeCompare(b.timestamp||''));
  pinned.forEach((post, idx) => {
    items.push({
      tipo_artefato: 'post_fixado',
      perfil: meta.username,
      trilha: meta.trilha,
      posicao: idx + 1,
      url: post.url,
      shortcode: post.shortCode,
      formato: post.type,
      caption: post.caption || '',
      display_url: post.displayUrl,
      video_url: post.videoUrl || '',
      likes: post.likesCount || 0,
      comments: post.commentsCount || 0,
      views: post.videoPlayCount || post.videoViewCount || 0,
      timestamp: post.timestamp,
      transcrever: meta.transcrever && post.type === 'Video',
      notas: meta.notas,
      origem: meta.origem,
      created_at: meta.created_at
    });
  });
}

// Destaques
if (meta.coletar_destaques && Array.isArray(highlightsData)) {
  highlightsData.forEach(h => {
    items.push({
      tipo_artefato: 'destaque',
      perfil: h.username || meta.username,
      trilha: meta.trilha,
      highlight_id: h.highlightId,
      titulo: h.highlightTitle || '',
      cover_url: h.coverImageUrl || h.coverImageUrlWrapped || '',
      transcrever: false,
      notas: meta.notas,
      origem: meta.origem,
      created_at: meta.created_at
    });
  });
}

return items.map(i => ({ json: i }));

// Modo PUBLICACAO — preparar payload pra apify/instagram-scraper
const body = $json.body;
return [{ json: {
  url: body.url,
  shortcode: body.shortcode,
  trilha: body.trilha,
  tipo_estrategico_manual: body.tipo_estrategico || null,
  etapa_funil_manual: body.etapa_funil || null,
  notas: body.notas || '',
  origem: body.origem || 'manual_form',
  created_at: body.created_at
}}];

const meta = $('Preparar Publicacao').first().json;
const data = $json;
const post = Array.isArray(data) ? data[0] : data;
if (!post || !post.shortCode) {
  throw new Error('Apify nao retornou post valido para ' + meta.url);
}
return [{ json: {
  tipo_artefato: 'publicacao_avulsa',
  perfil: post.ownerUsername || '',
  trilha: meta.trilha,
  url: post.url,
  shortcode: post.shortCode,
  formato: post.type,
  caption: post.caption || '',
  display_url: post.displayUrl,
  video_url: post.videoUrl || '',
  likes: post.likesCount || 0,
  comments: post.commentsCount || 0,
  views: post.videoPlayCount || post.videoViewCount || 0,
  timestamp: post.timestamp,
  transcrever: post.type === 'Video',
  tipo_estrategico_manual: meta.tipo_estrategico_manual,
  etapa_funil_manual: meta.etapa_funil_manual,
  notas: meta.notas,
  origem: meta.origem,
  created_at: meta.created_at
}}];

const item = $('Switch Transcrever?').first().json;
const trans = $json;
return [{ json: { ...item, transcricao: trans.text || '', language_code: trans.language_code || '', audio_duration_ms: trans.audio_duration || 0 } }];

// Classificacao heuristica determinista (mesma usada no banco offline)
const i = $json;
const caption = (i.caption || '') + ' ' + (i.transcricao || '');
const lc = caption.toLowerCase();

function matchAny(patterns) {
  return patterns.some(p => new RegExp(p, 'i').test(lc));
}

let tipo_estrategico = i.tipo_estrategico_manual;
if (!tipo_estrategico) {
  if (i.tipo_artefato === 'destaque') {
    const t = (i.titulo || '').toLowerCase();
    if (/quem sou|sobre mim|trajet|hist[oó]ria|apresent/.test(t)) tipo_estrategico = 'Quem Sou';
    else if (/result|transform|antes.*depois|case|sucesso|depoiment/.test(t)) tipo_estrategico = 'Resultados';
    else if (/m[eé]tod|protocolo|jornada|mentoria|clinic|tratament/.test(t)) tipo_estrategico = 'Metodologia/Produto';
    else if (/faq|d[uú]vid|pergunt|valor|investiment|pre[çc]/.test(t)) tipo_estrategico = 'FAQ';
    else if (/dica|educa|tutorial|passo|tip/.test(t)) tipo_estrategico = 'Dicas Grátis';
    else if (/oferta|comprar|vagas|inscri|link|bio|agend|whats/.test(t)) tipo_estrategico = 'Mentoria/Produto/Oferta';
    else if (/bastidor|vlog|rotina|home|pessoal|lifestyle/.test(t)) tipo_estrategico = 'Bastidores';
    else tipo_estrategico = 'Específico do Nicho';
  } else {
    const apresentacao = ['quem sou', 'me chamo', 'me apresent', 'trabalho com', 'atendo', 'especialista em', 'sobre mim', 'minha hist'];
    const prova = ['antes e depois', 'caso clínic', 'depoiment', 'transforma', 'resultado', 'paciente', 'aluno', 'aluna', 'mentorad', 'testemunh', 'evolu', 'jornada'];
    const oferta = ['agend[ae]', 'agendar', 'avalia[cç][aã]o', 'link na bio', 'clique no link', 'whatsapp', 'comente .* receb', 'quero o', 'aula gratuita', 'ebook'];
    const ap = matchAny(apresentacao); const pv = matchAny(prova); const of = matchAny(oferta);
    if (i.posicao === 1 && ap) tipo_estrategico = 'Apresentação';
    else if (i.posicao === 3 && of) tipo_estrategico = 'Oferta/CTA';
    else if (of) tipo_estrategico = 'Oferta/CTA';
    else if (pv) tipo_estrategico = 'Prova Social';
    else if (ap) tipo_estrategico = 'Apresentação';
    else tipo_estrategico = 'Indefinido';
  }
}

let etapa_funil = i.etapa_funil_manual;
if (!etapa_funil) {
  if (tipo_estrategico === 'Oferta/CTA') etapa_funil = 'ACAO';
  else if (tipo_estrategico === 'Prova Social' || tipo_estrategico === 'Resultados' || tipo_estrategico === 'Quem Sou') etapa_funil = 'CONFIANCA';
  else etapa_funil = 'DESCOBERTA';
}

return [{ json: { ...i, tipo_estrategico, etapa_funil } }];
